const rateLimiter = {};

function isAllowed(ip, maxRequests = 100, windowMs = 60000) {
  const now = Date.now();

  if (!rateLimiter[ip]) {
    rateLimiter[ip] = { count: 1, windowStart: now };
    return true;
  }

  const record = rateLimiter[ip];

  // Reset if window expired
  if (now - record.windowStart > windowMs) {
    record.count = 1;
    record.windowStart = now;
    return true;
  }

  // Check limit
  if (record.count >= maxRequests) {
    return false;  // Rate limited!
  }

  record.count++;
  return true;
}

